import { useMemo } from 'react';
import { generateVietQR, VietQROptions } from '@viet-qr/core';

export interface UseVietQRReturn {
  /** Chuỗi EMVCo payload (rỗng nếu lỗi) */
  payload: string;
  /** True nếu payload được tạo thành công */
  isValid: boolean;
  /** Thông báo lỗi nếu có */
  error: string | null;
}

/**
 * Hook tiện ích để sinh và quản lý VietQR payload một cách reactive.
 *
 * @example
 * const { payload, isValid, error } = useVietQR({
 *   bankId: 'VCB',
 *   accountNo: '1234567890',
 *   amount: 50000,
 * });
 */
export function useVietQR(options: VietQROptions): UseVietQRReturn {
  const { bankId, accountNo, accountName, amount, content, isCard } = options;

  const result = useMemo(() => {
    try {
      const payload = generateVietQR({ bankId, accountNo, accountName, amount, content, isCard });
      return { payload, isValid: true, error: null };
    } catch (e) {
      const message = e instanceof Error ? e.message : 'Unknown error';
      return { payload: '', isValid: false, error: message };
    }
  }, [bankId, accountNo, accountName, amount, content, isCard]);

  return result;
}
